using System;
using Xunit;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            var service = new NotificationService();

            service.SendNotification("Course", "101", EntityOperation.UPDATE, "teacher");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 101", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_UsesDisplayName()
        {
            var service = new NotificationService();

            service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "admin");

            var notification = service.ReceiveNotification();
            Assert.Contains("Engineering", notification.Message);
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.Contains("created", notification.Message);
            Assert.Contains("Test Student", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test Student", EntityOperation.UPDATE);

            var notification = service.ReceiveNotification();
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test Student", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var service = new NotificationService();
            var before = DateTime.Now;

            service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var service = new NotificationService();

            var notification = service.ReceiveNotification();

            // Queue may or may not be empty depending on other test runs (static queue)
            // But calling receive should not throw
        }

        [Fact]
        public void ReceiveNotification_ReturnsFifoOrder()
        {
            var service = new NotificationService();

            // Drain any existing notifications from the static queue
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var service = new NotificationService();

            // Should not throw - it's a no-op in the in-memory implementation
            service.MarkAsRead(1);
            service.MarkAsRead(999);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.SendNotification("Test", "1", EntityOperation.CREATE);

            service.Dispose();
            // Should not throw
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }
    }
}

