using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Student CreateTestStudent(string lastName = "Doe", string firstName = "John", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            CreateTestStudent("Smith", "Alice");
            CreateTestStudent("Jones", "Bob");

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastName()
        {
            CreateTestStudent("Zander", "Alice");
            CreateTestStudent("Adams", "Bob");

            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Equal("Adams", model[0].LastName);
            Assert.Equal("Zander", model[1].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            CreateTestStudent("Adams", "Alice");
            CreateTestStudent("Zander", "Bob");

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Equal("Zander", model[0].LastName);
            Assert.Equal("Adams", model[1].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDate()
        {
            CreateTestStudent("A", "A", new DateTime(2023, 9, 1));
            CreateTestStudent("B", "B", new DateTime(2021, 1, 1));

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Equal("B", model[0].LastName);
            Assert.Equal("A", model[1].LastName);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            CreateTestStudent("A", "A", new DateTime(2021, 1, 1));
            CreateTestStudent("B", "B", new DateTime(2023, 9, 1));

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Equal("B", model[0].LastName);
            Assert.Equal("A", model[1].LastName);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            CreateTestStudent("Smith", "Alice");
            CreateTestStudent("Jones", "Bob");

            var result = _controller.Index(null, null, "Smith", null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Single(model);
            Assert.Equal("Smith", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            CreateTestStudent("Smith", "Alice");
            CreateTestStudent("Jones", "Bob");

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Single(model);
            Assert.Equal("Alice", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "test", 5) as ViewResult;

            // When searchString is not null, page is set to 1
            Assert.NotNull(result);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            CreateTestStudent("Smith", "Alice");
            CreateTestStudent("Jones", "Bob");

            var result = _controller.Index(null, "Smith", null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsSortParmViewBags()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithSortOrder_SetsNameSortParmEmpty()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_WithDateSort_SetsDateSortParmToDateDesc()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = CreateTestStudent();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

