using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department CreateTestDepartment(string name = "Engineering", decimal budget = 100000m)
        {
            var department = new Department
            {
                Name = name,
                Budget = budget,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(department);
            _context.SaveChanges();
            return department;
        }

        private Instructor CreateTestInstructor(string lastName = "Smith", string firstName = "John")
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            CreateTestDepartment("Engineering");
            CreateTestDepartment("Science");

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<Department>>(result.Model);
            Assert.Equal(2, model.Count());
        }

        [Fact]
        public void Index_EmptyDb_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<Department>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var department = CreateTestDepartment();

            var result = _controller.Details(department.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(department.DepartmentID, model.DepartmentID);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsView()
        {
            CreateTestInstructor(); // Need at least one instructor for dropdown

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "NewDept",
                Budget = 50000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(department);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_AddsToDatabase()
        {
            var department = new Department
            {
                Name = "NewDept",
                Budget = 50000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(department);

            Assert.Equal(1, _context.Departments.Count());
            Assert.Equal("NewDept", _context.Departments.First().Name);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 50000m, StartDate = DateTime.Now };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(department, result.Model);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var department = CreateTestDepartment();

            var result = _controller.Edit(department.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(department.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = CreateTestDepartment();
            _context.Entry(department).State = EntityState.Detached;
            department.Name = "Updated";

            var result = _controller.Edit(department);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var department = CreateTestDepartment();
            _context.Entry(department).State = EntityState.Detached;
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var department = CreateTestDepartment();

            var result = _controller.Delete(department.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(department.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartment()
        {
            var department = CreateTestDepartment();

            _controller.DeleteConfirmed(department.DepartmentID);

            Assert.Equal(0, _context.Departments.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var department = CreateTestDepartment();

            var result = _controller.DeleteConfirmed(department.DepartmentID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        #endregion
    }
}

