using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/tmp/webroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/tmp/content");
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department CreateTestDepartment(string name = "Engineering")
        {
            var department = new Department
            {
                Name = name,
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(department);
            _context.SaveChanges();
            return department;
        }

        private Course CreateTestCourse(string title = "Intro to CS", int courseId = 1001, int? departmentId = null)
        {
            if (departmentId == null)
            {
                var dept = CreateTestDepartment();
                departmentId = dept.DepartmentID;
            }

            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = departmentId.Value
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithCourses()
        {
            CreateTestCourse("Course A", 1001);
            CreateTestCourse("Course B", 1002, _context.Departments.First().DepartmentID);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
            Assert.Equal(2, model.Count());
        }

        [Fact]
        public void Index_EmptyDb_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var course = CreateTestCourse();

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsView()
        {
            CreateTestDepartment();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var dept = CreateTestDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            var dept = CreateTestDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };

            _controller.Create(course, null);

            Assert.Equal(1, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            CreateTestDepartment();
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2001, Credits = 3 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(course, result.Model);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var dept = CreateTestDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var dept = CreateTestDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var course = CreateTestCourse();

            var result = _controller.Edit(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = CreateTestCourse();
            _context.Entry(course).State = EntityState.Detached;
            course.Title = "Updated Title";

            var result = _controller.Edit(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var course = CreateTestCourse();
            _context.Entry(course).State = EntityState.Detached;
            _controller.ModelState.AddModelError("Title", "Required");

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = CreateTestCourse();
            _context.Entry(course).State = EntityState.Detached;

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.txt");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = CreateTestCourse();
            _context.Entry(course).State = EntityState.Detached;

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.png");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var course = CreateTestCourse();

            var result = _controller.Delete(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourse()
        {
            var course = CreateTestCourse();

            _controller.DeleteConfirmed(course.CourseID);

            Assert.Equal(0, _context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var course = CreateTestCourse();

            var result = _controller.DeleteConfirmed(course.CourseID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        #endregion
    }
}

