using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor CreateTestInstructor(string lastName = "Smith", string firstName = "John")
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private Course CreateTestCourse(string title = "Intro to CS", int courseId = 1001)
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            CreateTestInstructor("Smith", "John");
            CreateTestInstructor("Jones", "Jane");

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_OrdersByLastName()
        {
            CreateTestInstructor("Zander", "Alice");
            CreateTestInstructor("Adams", "Bob");

            var result = _controller.Index(null, null) as ViewResult;
            var model = (InstructorIndexData)result.Model;

            Assert.Equal("Adams", model.Instructors.First().LastName);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructor = CreateTestInstructor();
            var course = CreateTestCourse();
            instructor.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            _context.SaveChanges();

            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = (InstructorIndexData)result.Model;

            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithoutIds_CoursesIsNull()
        {
            CreateTestInstructor();

            var result = _controller.Index(null, null) as ViewResult;
            var model = (InstructorIndexData)result.Model;

            Assert.Null(model.Courses);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
