using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResult_WithEnrollmentDateGroups()
        {
            _context.Students.Add(new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            });
            _context.Students.Add(new Student
            {
                LastName = "Jones",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 9, 1)
            });
            _context.Students.Add(new Student
            {
                LastName = "Brown",
                FirstMidName = "Bob",
                EnrollmentDate = new DateTime(2022, 9, 1)
            });
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<EnrollmentDateGroup>>(result.Model);
            var groups = model.ToList();
            Assert.Equal(2, groups.Count);
        }

        [Fact]
        public void About_EmptyDb_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<EnrollmentDateGroup>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void About_GroupsByEnrollmentDate()
        {
            _context.Students.Add(new Student
            {
                LastName = "A",
                FirstMidName = "A",
                EnrollmentDate = new DateTime(2023, 9, 1)
            });
            _context.Students.Add(new Student
            {
                LastName = "B",
                FirstMidName = "B",
                EnrollmentDate = new DateTime(2023, 9, 1)
            });
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;
            var model = ((IEnumerable<EnrollmentDateGroup>)result.Model).ToList();

            Assert.Single(model);
            Assert.Equal(2, model[0].StudentCount);
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult_WithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Contains("permission", (string)_controller.ViewBag.Message);
        }
    }
}

