using System;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ReturnsCombinedLastAndFirst()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            Assert.IsAssignableFrom<Person>(student);
            Assert.Equal("Doe", student.LastName);
            Assert.Equal("Jane", student.FirstMidName);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                LastName = "Wilson",
                FirstMidName = "Bob",
                HireDate = new DateTime(2020, 1, 1)
            };

            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Wilson, Bob", instructor.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };

            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_HireDate_CanBeSet()
        {
            var date = new DateTime(2020, 6, 15);
            var instructor = new Instructor { HireDate = date };

            Assert.Equal(date, instructor.HireDate);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 101,
                Title = "Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            Assert.Equal(101, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(4, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_TeachingMaterialImagePath_CanBeNull()
        {
            var course = new Course { CourseID = 1, Title = "Test", Credits = 3 };

            Assert.Null(course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_TeachingMaterialImagePath_CanBeSet()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 3,
                TeachingMaterialImagePath = "/uploads/test.jpg"
            };

            Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 150000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 5
            };

            Assert.Equal(1, department.DepartmentID);
            Assert.Equal("Engineering", department.Name);
            Assert.Equal(150000m, department.Budget);
            Assert.Equal(5, department.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var department = new Department { Name = "Test" };

            Assert.Null(department.InstructorID);
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 1
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeSet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Grade_HasExpectedValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_ReadAt_CanBeSet()
        {
            var readTime = DateTime.Now;
            var notification = new Notification
            {
                IsRead = true,
                ReadAt = readTime
            };

            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region CourseAssignment

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 101
            };

            Assert.Equal(1, assignment.InstructorID);
            Assert.Equal(101, assignment.CourseID);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 305"
            };

            Assert.Equal(1, office.InstructorID);
            Assert.Equal("Room 305", office.Location);
        }

        #endregion

        #region ViewModels

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2023, 9, 1),
                StudentCount = 15
            };

            Assert.Equal(new DateTime(2023, 9, 1), group.EnrollmentDate);
            Assert.Equal(15, group.StudentCount);
        }

        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new ContosoUniversity.Models.SchoolViewModels.AssignedCourseData
            {
                CourseID = 101,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(101, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var data = new ContosoUniversity.Models.SchoolViewModels.InstructorIndexData
            {
                Instructors = new[] { new Instructor { LastName = "Test", FirstMidName = "A", HireDate = DateTime.Now } },
                Courses = new[] { new Course { CourseID = 1, Title = "Test", Credits = 3 } },
                Enrollments = new[] { new Enrollment { EnrollmentID = 1 } }
            };

            Assert.Single(data.Instructors);
            Assert.Single(data.Courses);
            Assert.Single(data.Enrollments);
        }

        #endregion
    }
}

