        public void SchoolContext_CanAddOfficeAssignment()
        {
            using var context = TestDbContextFactory.Create();

            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Prof",
                HireDate = new DateTime(2020, 1, 1)
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            });
            context.SaveChanges();

            Assert.Equal(1, context.OfficeAssignments.Count());
        }

        [Fact]
        public void SchoolContext_Student_WithEnrollments_NavigationProperty()
        {
            using var context = TestDbContextFactory.Create();

            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            context.Students.Add(student);

            var dept = new Department
            {
                Name = "Test",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.B
            });
            context.SaveChanges();

            var loadedStudent = context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == student.ID);

            Assert.Single(loadedStudent.Enrollments);
        }
    }
}

